operation.add:
//order statuses change
$this->document->addScript('view/javascript/jquery/jquery.jeditable.mini.js');
$this->load->model('user/api');
$this->load->model('localisation/order_status');
  $api_info = $this->model_user_api->getApi($this->config->get('config_api_id'));

if ($api_info && $this->user->hasPermission('modify', 'sale/order')) {
    $session = new Session($this->config->get('session_engine'), $this->registry);

    $session->start();

    $this->model_user_api->deleteApiSessionBySessonId($session->getId());

    $this->model_user_api->addApiSession($api_info['api_id'], $session->getId(), $this->request->server['REMOTE_ADDR']);

    $session->data['api_id'] = $api_info['api_id'];

    $data['api_token'] = $session->getId();
} else {
    $data['api_token'] = '';
}
    $data['order_statuses'] = $this->model_localisation_order_status->getOrderStatuses();
     foreach ($data['order_statuses'] as $order_status) {
                $status_array[$order_status['order_status_id']] = $order_status['name'];
        }
        $data['status_json'] = json_encode($status_array);
    //order statuses change
